[CmdletBinding()]
param([ValidateSet('T0','T1','T2','T3','T4')][string]$Tier='T1',[int]$ChangedFiles=0,[switch]$HasExternalState,[switch]$Json)
$ErrorActionPreference='Stop';$base=@{T0=1;T1=5;T2=18;T3=45;T4=90}[$Tier];$extra=[math]::Min(30,[math]::Max(0,$ChangedFiles-1)*2);if($HasExternalState){$extra+=15};$minutes=$base+$extra;$advice=if($Tier -in @('T0','T1') -and !$HasExternalState){'Use core route and focused verification.'}elseif($Tier -in @('T3','T4')){'Budget independent verification and evidence capture.'}else{'Use proportional selection; avoid loading unrelated packs.'};$result=[ordered]@{schemaVersion=1;tier=$Tier;changedFiles=$ChangedFiles;externalState=$HasExternalState.IsPresent;estimatedMinutes=$minutes;confidence='HEURISTIC';advice=$advice;limitations='This is a planning estimate, not model-token telemetry or a cost quote.';automaticModelChange=$false};if($Json){$result|ConvertTo-Json}else{$result|Format-List}
